// Determine tier from Parse Sentiment (source of truth)
let tier = 'normal';
try { tier = $('Parse Sentiment').first().json.tier || 'normal'; } catch(e) { tier = input.tier || 'normal'; }

// Tiered responses MUST always respond — defense-in-depth override
// regardless of classifier's should_suppress value
const TIERED_MUST_RESPOND = ['tier_1_confused', 'tier_2_hostile', 'tier_3_optout', 'emotional', 'turnaround', 'booking', 'declined_meeting'];
const isTiered = TIERED_MUST_RESPOND.includes(tier);

if (!responseText) {
  const fallbacks = {
    emotional: "I'm really sorry to hear that. No pressure at all, take care of yourself.",
    tier_2_hostile: "Understood, no worries at all.",
    tier_3_optout: "Got it, I'll stop reaching out. Wishing you the best.",
    tier_1_confused: "No worries. Happy to help clarify anything."
  };

  const fallback = fallbacks[tier];
  if (fallback) {
    return [{ json: { ...input, responseText: fallback, output: fallback, shouldRespond: true, silenceReason: 'empty_ai_fallback_' + tier } }];
  }

  // Normal tier with empty response — suppress
  return [{ json: { ...input, shouldRespond: false, silenceReason: 'empty_ai_response' } }];
}

// Outbound always sends
if (direction === 'outbound') {
  return [{ json: { ...input, responseText: responseText, output: responseText, shouldRespond: true, silenceReason: 'outbound_always_sends' } }];
}

// Tiered responses ALWAYS respond — classifier should_suppress is ignored
if (isTiered) {
  return [{ json: { ...input, responseText: responseText, output: responseText, shouldRespond: true, silenceReason: 'tiered_always_responds_' + tier } }];
}

// For normal tier: respect classifier's suppress decision (cold ack logic)
const sentimentData = $('Parse Sentiment').first().json;
const shouldSuppress = sentimentData.should_suppress === true;
const suppressReason = sentimentData.suppress_reason || 'none';

if (shouldSuppress) {
  return [{ json: { ...input, responseText: responseText, output: responseText, shouldRespond: false, silenceReason: suppressReason } }];
}

return [{ json: { ...input, responseText: responseText, output: responseText, shouldRespond: true, silenceReason: 'classifier_says_respond' } }];
